Send Freeform Message.code:
// Send a freeform text message via the WhatsApp Business API.
// Only allowed within the 24-hour customer-service window.
request('POST', 'messages', {
  messaging_product: 'whatsapp',
  to:   $.data.toPhone,        // E.164, no '+' (e.g. '254712345678')
  type: 'text',
  text: { body: $.data.body },
});

Send Media Message.code:
// Send a media attachment. `type` is one of image | video | document | audio.
request('POST', 'messages', {
  messaging_product: 'whatsapp',
  to:   $.data.toPhone,
  type: 'image',
  image: {
    // Either a public URL...
    link: $.data.imageUrl,
    // ...or `id` referencing a previously uploaded media id.
    caption: $.data.caption,
  },
});

Send Template Message.code:
// Send an approved WhatsApp template message.
request('POST', 'messages', {
  messaging_product: 'whatsapp',
  to:   $.data.toPhone,
  type: 'template',
  template: {
    name: 'hello_world',
    language: { code: 'en_US' },
    // Template body variables, if your template uses {{1}}, {{2}}, ...
    // components: [{
    //   type: 'body',
    //   parameters: [{ type: 'text', text: $.data.firstName }],
    // }],
  },
});
